import React, { useEffect, useState } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ jiraData, onSelectUserStory, onClose, isSidebarVisible }) {
  const [loading, setLoading] = useState(true);  // State to manage loading status
  const [error, setError] = useState(null);  // State to handle errors if they occur

  // Handle the error if no Jira data is available
  useEffect(() => {
    if (!jiraData || jiraData.length === 0) {
      setError('No Jira data available.');
    } else {
      setError(null);  // Reset error if there is Jira data
      setLoading(false);  // Set loading to false when data is available
    }
  }, [jiraData]);

  const handleUserStoryClick = (story) => {
    // Call the parent function to update the story in ChatBox
    onSelectUserStory(story);
    onClose(); // Optionally close the sidebar when a story is selected
  };

  return (
    <div className={`import-sidebar ${isSidebarVisible ? 'visible' : ''}`}>
      <button className="close-btn" onClick={onClose}>X</button>
      <div className="sidebar-title"><strong>Imported Jira User Stories</strong></div>

      {loading && <div>Loading...</div>}  {/* Display loading indicator */}
      {error && <div className="error">{error}</div>}  {/* Display error if exists */}

      {/* Display Jira Stories */}
      <div className="jira-stories">
        {jiraData && jiraData.length > 0 ? (
          <div>
            {jiraData.map((story) => (
              <div
                key={story.id}
                onClick={() => handleUserStoryClick(story)} // Handle click on user story
                className="story-item"
              >
                <p>{story.summary}</p>
              </div>
            ))}
          </div>
        ) : (
          <div>No details available.</div>
        )}
      </div>
    </div>
  );
}

export default ImportDataSidebar;
